import{_ as d,o as r,c as e,ag as a}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"クラスタータイプ一覧","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cluster-types.md","filePath":"reference/cluster-types.md"}'),h={name:"reference/cluster-types.md"};function o(l,t,i,n,s,b){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="クラスタータイプ一覧" tabindex="-1">クラスタータイプ一覧 <a class="header-anchor" href="#クラスタータイプ一覧" aria-label="Permalink to &quot;クラスタータイプ一覧&quot;">​</a></h1><p>ConMas i-Reporter で使用できる全 <strong>38 種類</strong> のクラスタータイプです。カテゴリごとに分類しています。</p><div class="tip custom-block"><p class="custom-block-title">AI 自動検出対象</p><p>★ マーク付きのタイプは AI 解析で自動検出されます。それ以外はクラスターエディタの作成モードで手動追加できます。</p></div><hr><h2 id="テキスト" tabindex="-1">テキスト <a class="header-anchor" href="#テキスト" aria-label="Permalink to &quot;テキスト&quot;">​</a></h2><p>テキスト入力に関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>AI</th><th>用途</th></tr></thead><tbody><tr><td>KeyboardText</td><td>キーボードテキスト</td><td>30</td><td>★</td><td>キーボードで文字を入力する一般的なテキスト欄</td></tr><tr><td>Handwriting</td><td>手書きデジタル</td><td>119</td><td>★</td><td>手書き文字をデジタル変換して入力（署名など）</td></tr><tr><td>FixedText</td><td>手書きノート形式</td><td>20</td><td>★</td><td>手書き入力をそのまま画像として保存</td></tr><tr><td>FreeText</td><td>手書きフリーメモ</td><td>10</td><td></td><td>ホワイトボード風のフリーメモ</td></tr></tbody></table><p><strong>よくある使い分け:</strong></p><ul><li>氏名・住所・備考 → <strong>KeyboardText</strong></li><li>署名・印鑑欄 → <strong>Handwriting</strong></li><li>手書きのスケッチやメモ → <strong>FixedText</strong> / <strong>FreeText</strong></li></ul><hr><h2 id="数値・計算" tabindex="-1">数値・計算 <a class="header-anchor" href="#数値・計算" aria-label="Permalink to &quot;数値・計算&quot;">​</a></h2><p>数値入力と計算に関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>AI</th><th>用途</th></tr></thead><tbody><tr><td>Numeric</td><td>数値選択</td><td>60</td><td></td><td>スライダーやステッパーで数値を選択</td></tr><tr><td>InputNumeric</td><td>数値</td><td>65</td><td>★</td><td>テンキーで数値を直接入力</td></tr><tr><td>NumberHours</td><td>時間数</td><td>110</td><td></td><td>時間数（○時間○分）の入力</td></tr><tr><td>Calculate</td><td>計算式</td><td>67</td><td>★</td><td>他クラスターの値を参照して自動計算</td></tr></tbody></table><p><strong>よくある使い分け:</strong></p><ul><li>温度・数量・金額 → <strong>InputNumeric</strong></li><li>合計・小計 → <strong>Calculate</strong>（Excel の数式セルから自動検出）</li><li>作業時間 → <strong>NumberHours</strong></li></ul><hr><h2 id="日付・時刻" tabindex="-1">日付・時刻 <a class="header-anchor" href="#日付・時刻" aria-label="Permalink to &quot;日付・時刻&quot;">​</a></h2><p>日付と時刻の入力に関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>AI</th><th>用途</th></tr></thead><tbody><tr><td>Date</td><td>年月日</td><td>40</td><td>★</td><td>ドラムロール式の日付入力</td></tr><tr><td>CalendarDate</td><td>カレンダー年月日</td><td>111</td><td></td><td>カレンダー UI から日付を選択</td></tr><tr><td>Time</td><td>時刻</td><td>50</td><td>★</td><td>時刻（HH:mm）の入力</td></tr><tr><td>TimeCalculate</td><td>時刻計算</td><td>55</td><td></td><td>時刻同士の差分を自動計算</td></tr></tbody></table><p><strong>よくある使い分け:</strong></p><ul><li>実施日・記入日 → <strong>Date</strong></li><li>期間指定（開始〜終了） → <strong>CalendarDate</strong></li><li>開始時刻・終了時刻 → <strong>Time</strong></li><li>作業時間（終了 - 開始） → <strong>TimeCalculate</strong></li></ul><hr><h2 id="選択・チェック" tabindex="-1">選択・チェック <a class="header-anchor" href="#選択・チェック" aria-label="Permalink to &quot;選択・チェック&quot;">​</a></h2><p>選択肢やチェックボックスに関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>AI</th><th>用途</th></tr></thead><tbody><tr><td>Check</td><td>チェック</td><td>90</td><td>★</td><td>単一のチェックボックス</td></tr><tr><td>MultipleChoiceNumber</td><td>トグル選択</td><td>123</td><td></td><td>トグル切替式の数値選択</td></tr><tr><td>MCNCalculate</td><td>トグル集計</td><td>124</td><td></td><td>トグル選択の集計計算</td></tr><tr><td>Select</td><td>単一選択</td><td>70</td><td>★</td><td>ドロップダウン等で1つを選択</td></tr><tr><td>MultiSelect</td><td>複数選択</td><td>80</td><td></td><td>ドロップダウン等で複数を選択</td></tr><tr><td>SelectMaster</td><td>マスター選択</td><td>125</td><td></td><td>マスターデータから選択</td></tr></tbody></table><p><strong>よくある使い分け:</strong></p><ul><li>合否・確認チェック → <strong>Check</strong></li><li>区分・ステータス（1つ選択） → <strong>Select</strong></li><li>該当項目を複数チェック → <strong>MultiSelect</strong></li><li>マスターテーブルから検索して選択 → <strong>SelectMaster</strong></li></ul><hr><h2 id="メディア・描画" tabindex="-1">メディア・描画 <a class="header-anchor" href="#メディア・描画" aria-label="Permalink to &quot;メディア・描画&quot;">​</a></h2><p>画像や描画に関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>AI</th><th>用途</th></tr></thead><tbody><tr><td>Image</td><td>画像</td><td>100</td><td>★</td><td>写真撮影・画像添付</td></tr><tr><td>FreeDraw</td><td>フリードロー</td><td>15</td><td></td><td>フリーハンドで描画</td></tr><tr><td>DrawingImage</td><td>ピン打ち</td><td>128</td><td></td><td>画像上にピンを配置</td></tr><tr><td>DrawingPinNo</td><td>ピンNo.配置</td><td>129</td><td></td><td>ピン番号を図面上に配置</td></tr><tr><td>PinItemTableNo</td><td>ピンNo.</td><td>130</td><td></td><td>ピン番号の参照表示</td></tr><tr><td>AudioRecording</td><td>録音</td><td>131</td><td></td><td>音声の録音・添付</td></tr></tbody></table><p><strong>よくある使い分け:</strong></p><ul><li>現場写真 → <strong>Image</strong></li><li>手書きのスケッチ → <strong>FreeDraw</strong></li><li>図面上の指摘箇所 → <strong>DrawingImage</strong> + <strong>DrawingPinNo</strong></li></ul><hr><h2 id="ワークフロー" tabindex="-1">ワークフロー <a class="header-anchor" href="#ワークフロー" aria-label="Permalink to &quot;ワークフロー&quot;">​</a></h2><p>帳票の承認フローに関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>用途</th></tr></thead><tbody><tr><td>Create</td><td>作成</td><td>116</td><td>帳票の作成者情報</td></tr><tr><td>Inspect</td><td>査閲</td><td>117</td><td>査閲者の承認欄</td></tr><tr><td>Approve</td><td>承認</td><td>118</td><td>最終承認者の承認欄</td></tr><tr><td>Registration</td><td>帳票登録者</td><td>112</td><td>帳票を登録したユーザー名</td></tr><tr><td>RegistrationDate</td><td>帳票登録年月日</td><td>113</td><td>帳票の登録日時</td></tr><tr><td>LatestUpdate</td><td>帳票更新者</td><td>114</td><td>最後に更新したユーザー名</td></tr><tr><td>LatestUpdateDate</td><td>帳票更新年月日</td><td>115</td><td>最後の更新日時</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>ワークフロー系タイプは AI 自動検出の対象外です。必要に応じて手動で追加してください。</p></div><hr><h2 id="読取・スキャン" tabindex="-1">読取・スキャン <a class="header-anchor" href="#読取・スキャン" aria-label="Permalink to &quot;読取・スキャン&quot;">​</a></h2><p>バーコードや位置情報の読取に関するタイプです。</p><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>用途</th></tr></thead><tbody><tr><td>QRCode</td><td>バーコード</td><td>121</td><td>QR コード・バーコードの表示</td></tr><tr><td>CodeReader</td><td>コードリーダー</td><td>122</td><td>カメラでバーコードを読取</td></tr><tr><td>Gps</td><td>GPS位置情報</td><td>120</td><td>現在地の緯度経度を記録</td></tr><tr><td>Scandit</td><td>SCANDIT</td><td>132</td><td>Scandit SDK によるバーコード読取</td></tr><tr><td>EdgeOCR</td><td>EdgeOCR</td><td>133</td><td>Edge OCR によるテキスト読取</td></tr></tbody></table><hr><h2 id="アクション" tabindex="-1">アクション <a class="header-anchor" href="#アクション" aria-label="Permalink to &quot;アクション&quot;">​</a></h2><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>用途</th></tr></thead><tbody><tr><td>Action</td><td>アクション</td><td>126</td><td>ボタン押下でアクションを実行</td></tr></tbody></table><hr><h2 id="その他" tabindex="-1">その他 <a class="header-anchor" href="#その他" aria-label="Permalink to &quot;その他&quot;">​</a></h2><table tabindex="0"><thead><tr><th>タイプ名</th><th>日本語名</th><th>値</th><th>用途</th></tr></thead><tbody><tr><td>LoginUser</td><td>ログインユーザー</td><td>127</td><td>ログイン中のユーザー名を自動表示</td></tr></tbody></table>',48)])])}const u=d(h,[["render",o]]);export{g as __pageData,u as default};
